#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 15;
_i128 n,a[N],b[N],m[N],y[N];
_i128 MOD,Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
_i128 exGCD(_i128 a,_i128 b,_i128 &x,_i128 &y){
    if(!b){x=1,y=0;return a;}
    _i128 yu=exGCD(b,a%b,x,y);
    _i128 tmp=x;x=y,y=tmp-a/b*y;
    return yu;
}
int main(){
    n=read();MOD=1;
    for(int i=1;i<=n;i++)
        a[i]=read(),b[i]=read();
    for(int i=1;i<=n;i++)MOD*=a[i];
    for(int i=1;i<=n;i++){
        m[i]=MOD/a[i];
        _i128 X=0,Y=0;
        exGCD(m[i],a[i],X,Y);
        y[i]=X;
    }for(int i=1;i<=n;i++)
        Ans+=((m[i]*b[i])%MOD*y[i])%MOD,Ans%=MOD;
    Ans=(Ans+MOD)%MOD;
    cout<<(LL)(Ans)<<"\n";
    return 0;
}
